import React, { useState, useEffect, useRef } from 'react';
import { ChevronDown, Check } from 'lucide-react';

interface MultiSelectDropdownProps {
  label: string;
  options: string[];
  selected: string[];
  onToggle: (opt: string) => void;
  placeholder: string;
}

const MultiSelectDropdown: React.FC<MultiSelectDropdownProps> = ({ label, options, selected, onToggle, placeholder }) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => { 
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setIsOpen(false); 
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="space-y-1.5 relative w-full" ref={containerRef}>
      <label className="text-[11px] font-bold text-slate-500 uppercase tracking-widest pl-1">{label}</label>
      <div 
        className="w-full h-10 px-3 bg-slate-50 border border-slate-200 rounded-lg text-sm flex items-center justify-between cursor-pointer hover:border-blue-400 transition-all shadow-sm"
        onClick={() => setIsOpen(!isOpen)}
      >
        <span className={`truncate ${selected.length ? 'text-blue-700 font-bold' : 'text-slate-400'}`}>
          {selected.length ? `已选 ${selected.length} 个` : placeholder}
        </span>
        <ChevronDown size={14} className={`text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </div>
      {isOpen && (
        <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-slate-200 rounded-xl shadow-xl z-[100] overflow-hidden py-1 min-w-[180px] animate-in fade-in slide-in-from-top-1 duration-200">
          <div className="max-h-60 overflow-y-auto">
            {options.map(opt => (
              <div key={opt} className="px-4 py-2 hover:bg-blue-50 flex items-center gap-3 cursor-pointer text-sm" onClick={() => onToggle(opt)}>
                <div className={`w-4 h-4 border rounded flex items-center justify-center transition-colors ${selected.includes(opt) ? 'bg-blue-500 border-blue-500 text-white' : 'border-slate-300'}`}>{selected.includes(opt) && <Check size={10} />}</div>
                <span className={selected.includes(opt) ? 'text-blue-600 font-bold' : ''}>{opt}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default MultiSelectDropdown;

import React, { useState } from 'react';
import { Search, RotateCcw, Download, Upload, Edit3 } from 'lucide-react';
import MultiSelectDropdown from './MultiSelectDropdown';
import { COUNTRY_FULL_DATA } from '../constants';

const CountryManagement = () => {
  const [searchParams, setSearchParams] = useState({ names: '', codes: '', iso2s: '', tiers: [] as string[] });
  const [filteredData, setFilteredData] = useState(COUNTRY_FULL_DATA);
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 15;

  const handleQuery = () => {
    let result = [...COUNTRY_FULL_DATA];
    if (searchParams.names) result = result.filter(i => i.name.includes(searchParams.names));
    if (searchParams.codes) result = result.filter(i => i.code.includes(searchParams.codes));
    if (searchParams.iso2s) result = result.filter(i => i.iso2.includes(searchParams.iso2s));
    if (searchParams.tiers.length > 0) result = result.filter(i => searchParams.tiers.includes(i.tier));
    setFilteredData(result); 
    setCurrentPage(1);
  };

  const handleDownload = () => {
    const csvContent = "\ufeff国家,地区码,二字码,tier\n";
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.setAttribute('download', '国家导入模板.csv');
    document.body.appendChild(link); link.click(); document.body.removeChild(link);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <section className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 items-end">
          <div className="space-y-1.5"><label className="text-[11px] font-bold text-slate-500 uppercase pl-1">国家/地区名</label><input type="text" placeholder="输入名称" className="w-full h-10 px-3 bg-slate-50 border rounded-lg text-sm" value={searchParams.names} onChange={e=>setSearchParams({...searchParams, names:e.target.value})} /></div>
          <div className="space-y-1.5"><label className="text-[11px] font-bold text-slate-500 uppercase pl-1">地区码</label><input type="text" placeholder="如: CHN" className="w-full h-10 px-3 bg-slate-50 border rounded-lg text-sm" value={searchParams.codes} onChange={e=>setSearchParams({...searchParams, codes:e.target.value})} /></div>
          <div className="space-y-1.5"><label className="text-[11px] font-bold text-slate-500 uppercase pl-1">二字码</label><input type="text" placeholder="如: CN" className="w-full h-10 px-3 bg-slate-50 border rounded-lg text-sm" value={searchParams.iso2s} onChange={e=>setSearchParams({...searchParams, iso2s:e.target.value})} /></div>
          <MultiSelectDropdown label="Tier 分类" options={['T1', 'T2', 'T3', 'T4']} selected={searchParams.tiers} onToggle={opt => setSearchParams(prev => ({...prev, tiers: prev.tiers.includes(opt)?prev.tiers.filter(x=>x!==opt):[...prev.tiers, opt]}))} placeholder="选择 Tier" />
        </div>
        <div className="flex justify-end gap-3 pt-6 border-t mt-4">
          <button onClick={()=>{setSearchParams({names:'', codes:'', iso2s:'', tiers:[]}); setFilteredData(COUNTRY_FULL_DATA);}} className="h-10 px-6 font-bold text-slate-500 bg-slate-100 rounded-lg flex items-center gap-2"><RotateCcw size={16}/> 重置</button>
          <button onClick={handleQuery} className="h-10 px-10 font-bold bg-blue-600 text-white rounded-lg shadow-md hover:bg-blue-700 transition-all flex items-center gap-2"><Search size={16}/> 查询</button>
        </div>
      </section>
      <section className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b bg-slate-50/50 flex justify-between items-center">
          <span className="text-[11px] font-black text-slate-500 uppercase px-3 italic">Master Data View</span>
          <div className="flex gap-2">
            <button onClick={handleDownload} className="h-9 px-4 text-xs font-bold text-slate-600 bg-white border rounded-lg flex items-center gap-2 shadow-sm"><Download size={14}/> 下载模板</button>
            <button className="h-9 px-4 text-xs font-bold text-white bg-blue-600 rounded-lg flex items-center gap-2"><Upload size={14}/> 批量上传</button>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/80 text-slate-400 text-[10px] uppercase font-black border-b h-14">
                <th className="px-6 py-4">ID</th><th className="px-6 py-4">国家/地区</th><th className="px-6 py-4">地区码</th><th className="px-6 py-4">二字码</th><th className="px-6 text-center">Tier</th><th className="px-6 text-center">本地货币</th><th className="px-6 text-center">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.slice((currentPage-1)*pageSize, currentPage*pageSize).map(item => (
                <tr key={item.id} className="hover:bg-blue-50/10 transition-colors h-14">
                  <td className="px-6 text-xs font-mono text-slate-400">{item.id}</td><td className="px-6 text-sm font-bold text-slate-800">{item.name}</td>
                  <td className="px-6 text-sm font-mono text-slate-500">{item.code}</td><td className="px-6 text-sm font-mono text-slate-500">{item.iso2}</td>
                  <td className="px-6 text-center"><span className="px-3 py-1 rounded-md text-[10px] font-black uppercase bg-emerald-500 text-white shadow-sm">{item.tier}</span></td>
                  <td className="px-6 text-xs font-bold text-slate-500 text-center uppercase tracking-tight">{item.currency}</td>
                  <td className="px-6 text-center"><button className="p-2 text-blue-500 hover:bg-blue-100 rounded-lg transition-all"><Edit3 size={15}/></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </div>
  );
};

export default CountryManagement;

import React, { useState, useMemo } from 'react';
import { Plus, Trash2, Download, Check, Edit3 } from 'lucide-react';
import MultiSelectDropdown from './MultiSelectDropdown';
import { INITIAL_COST_DATA, PROJECTS, SYSTEM_CHANNELS } from '../constants';

const CostManagement = () => {
  const [data, setData] = useState(INITIAL_COST_DATA);
