          <MultiSelectDropdown label="媒体多选" options={[...SYSTEM_CHANNELS, 'ASA']} selected={filters.media} onToggle={opt=>setFilters(prev=>({...prev, media: prev.media.includes(opt)?prev.media.filter(x=>x!==opt):[...prev.media, opt]}))} placeholder="选择媒体" />
          <div className="flex gap-2 h-10"><button onClick={()=>setFilteredData(data)} className="flex-1 font-bold bg-slate-100 rounded-lg">重置</button><button onClick={handleQuery} className="flex-[1.5] font-bold bg-blue-600 text-white rounded-lg shadow-md active:scale-95 transition-all">查询</button></div>
        </div>
