const generateReportData = (filters: any) => {
  // Determine grouping columns based on split dimensions
  const groups = filters.splitDimensions.length > 0 ? filters.splitDimensions : ['无细分'];
  const count = 25; // Generate 25 rows

  return Array.from({ length: count }).map((_, idx) => {
    const row: any = { id: idx };
    // Date Column
    row['日期'] = '2026-02-11';

    // Dimension Columns
    if (filters.splitDimensions.includes('游戏')) row['游戏'] = filters.games.length === 1 ? filters.games[0] : `${filters.project || 'Project'}-${['Android', 'iOS'][idx % 2]}`;
    if (filters.splitDimensions.includes('归属')) row['归属'] = idx % 3 === 0 ? '自然量' : '广告量';
    if (filters.splitDimensions.includes('媒体')) row['媒体'] = SYSTEM_CHANNELS[idx % SYSTEM_CHANNELS.length];
    if (filters.splitDimensions.includes('Tier')) row['Tier'] = `T${(idx % 4) + 1}`;
    if (filters.splitDimensions.includes('国家')) row['国家'] = ['US', 'CN', 'JP', 'KR', 'GB'][idx % 5];

    // Basic Metrics
    row['花销'] = (Math.random() * 5000).toFixed(2);
    row['安装'] = Math.floor(Math.random() * 1000);
    row['CPA'] = (parseFloat(row['花销']) / (row['安装'] || 1)).toFixed(2);

    // Dynamic Cohort Metrics
    filters.cohortMetrics.forEach((metric: string) => {
      filters.metricDays.forEach((day: string) => {
        const key = `${metric} D${day}`;
        if (metric.includes('率') || metric.includes('ROI')) {
           row[key] = (Math.random() * (metric.includes('ROI') ? 2 : 100)).toFixed(2) + '%';
        } else {
           row[key] = (Math.random() * 100).toFixed(2);
        }
      });
    });
    return row;
  });
};

