import React, { useState, useMemo, useEffect } from 'react';
import { Search, ChevronDown, ChevronUp, Save, FileDown, Layers, BarChart3, Settings2, Plus, X, Calendar } from 'lucide-react';
import MultiSelectDropdown from './MultiSelectDropdown';
import { COUNTRY_FULL_DATA, PROJECTS } from '../constants';

// --- Constants & Options ---
const TIME_DIMENSIONS = [
  { value: 'daily', label: '日报 (Day)' },
  { value: 'weekly', label: '周报 (Week)' },
  { value: 'monthly', label: '月报 (Month)' },
  { value: 'yearly', label: '年报 (Year)' }
];

const SPLIT_DIMENSIONS = ['游戏', '归属', '媒体', 'Tier', '国家'];

const COHORT_METRICS = [
  '留存人数', '留存率', '付费留存人数', '付费留存率',
  '付费金额', 'LTV', 'ARPPU', 'ROI',
  '累计付费人数', '累计付费次数', '累计付费率',
  '总储值金额', '总ROI'
];

const AD_CHANNELS = ['Facebook', 'Google Ads', 'TikTok', 'ASA', 'Applovin', 'Unity', 'IronSource'];
const ORGANIC_CHANNELS = ['Organic', 'Other'];

const GENERATE_DAYS = () => {
  const days = [];
  for (let i = 1; i <= 90; i++) days.push(String(i));
  for (let i = 90; i <= 720; i += 30) {
    if (!days.includes(String(i))) days.push(String(i));
  }
  return days;
};
const METRIC_DAYS_OPTIONS = GENERATE_DAYS();
const YEAR_OPTIONS = Array.from({length: 5}, (_, i) => String(2024 + i)); // 2024-2028

const SAVED_REPORTS_MOCK = [
  { id: 1, name: 'DawnGod US ROI Report' },
  { id: 2, name: 'Global LTV Analysis' },
  { id: 3, name: 'Weekly Retention Check' }
];

// --- Mock Data Generator ---
const generateReportData = (filters: any) => {
  const count = 25; // Generate 25 rows

  return Array.from({ length: count }).map((_, idx) => {
    const row: any = { id: idx };
    // Date Column Logic based on dimension
    if (filters.timeDim === 'weekly') row['日期'] = `2026-W${10 + (idx % 5)}`;
    else if (filters.timeDim === 'monthly') row['日期'] = `2026-${String(1 + (idx % 12)).padStart(2,'0')}`;
    else if (filters.timeDim === 'yearly') row['日期'] = `202${6 + (idx % 2)}`;
    else row['日期'] = '2026-02-11';

    // Dimension Columns
    if (filters.splitDimensions.includes('游戏')) row['游戏'] = filters.games.length === 1 ? filters.games[0] : `${filters.project || 'Project'}-${['Android', 'iOS'][idx % 2]}`;
    if (filters.splitDimensions.includes('归属')) row['归属'] = idx % 3 === 0 ? '自然量' : '广告量';
    if (filters.splitDimensions.includes('媒体')) row['媒体'] = filters.media.length > 0 ? filters.media[idx % filters.media.length] : (idx % 3 === 0 ? 'Organic' : 'Facebook');
    if (filters.splitDimensions.includes('Tier')) row['Tier'] = filters.tiers.length > 0 ? filters.tiers[idx % filters.tiers.length] : `T${(idx % 4) + 1}`;
    if (filters.splitDimensions.includes('国家')) row['国家'] = filters.countries.length > 0 ? filters.countries[idx % filters.countries.length] : ['US', 'CN', 'JP', 'KR', 'GB'][idx % 5];

    // Basic Metrics
    row['花销'] = (Math.random() * 5000).toFixed(2);
    row['安装'] = Math.floor(Math.random() * 1000);
    row['CPA'] = (parseFloat(row['花销']) / (row['安装'] || 1)).toFixed(2);

    // Dynamic Cohort Metrics
    filters.cohortMetrics.forEach((metric: string) => {
      filters.metricDays.forEach((day: string) => {
        const key = `${metric} D${day}`;
        if (metric.includes('率') || metric.includes('ROI')) {
           row[key] = (Math.random() * (metric.includes('ROI') ? 2 : 100)).toFixed(2) + '%';
        } else {
           row[key] = (Math.random() * 100).toFixed(2);
        }
      });
    });
    return row;
  });
};

