import React, { useState, useMemo, useEffect } from 'react';
import { Search, ChevronDown, ChevronUp, Save, FileDown, Layers, BarChart3, Settings2, Plus, X, Calendar, Clock } from 'lucide-react';
import MultiSelectDropdown from './MultiSelectDropdown';
import { COUNTRY_FULL_DATA, PROJECTS } from '../constants';

// --- Constants & Options ---
const TIME_DIMENSIONS = [
  { value: 'daily', label: '日报 (Day)' },
  { value: 'weekly', label: '周报 (Week)' },
  { value: 'monthly', label: '月报 (Month)' },
  { value: 'yearly', label: '年报 (Year)' }
];

const SPLIT_DIMENSIONS = ['游戏', '归属', '媒体', 'Tier', '国家'];

const COHORT_METRICS = [
  '留存人数', '留存率', '付费留存人数', '付费留存率',
  '付费金额', 'LTV', 'ARPPU', 'ROI',
  '累计付费人数', '累计付费次数', '累计付费率',
  '总储值金额', '总ROI'
];

const AD_CHANNELS = ['Facebook', 'Google Ads', 'TikTok', 'ASA', 'Applovin', 'Unity', 'IronSource'];
const ORGANIC_CHANNELS = ['Organic', 'Other'];

const GENERATE_DAYS = () => {
  const days = [];
  for (let i = 1; i <= 90; i++) days.push(String(i));
  for (let i = 90; i <= 720; i += 30) {
    if (!days.includes(String(i))) days.push(String(i));
  }
  return days;
};
const METRIC_DAYS_OPTIONS = GENERATE_DAYS();
const YEAR_OPTIONS = Array.from({length: 5}, (_, i) => String(2024 + i)); // 2024-2028

const SAVED_REPORTS_MOCK = [
  { id: 1, name: 'DawnGod US ROI Report' },
  { id: 2, name: 'Global LTV Analysis' },
  { id: 3, name: 'Weekly Retention Check' }
];

// --- Mock Data Generator ---
const generateReportData = (filters: any) => {
  const count = 25; // Generate 25 rows

  return Array.from({ length: count }).map((_, idx) => {
    const row: any = { id: idx };

    // 1. Date Column Logic
    if (filters.timeDim === 'weekly') row['日期'] = `2026-W${10 + (idx % 5)}`;
    else if (filters.timeDim === 'monthly') row['日期'] = `2026-${String(1 + (idx % 12)).padStart(2,'0')}`;
    else if (filters.timeDim === 'yearly') row['日期'] = `202${6 + (idx % 2)}`;
    else row['日期'] = `2026-02-${String(10 + (idx % 15)).padStart(2, '0')}`;

    // 2. Dimension Columns
    if (filters.splitDimensions.includes('游戏')) row['游戏'] = filters.games.length === 1 ? filters.games[0] : `${filters.project || 'Project'}-${['Android', 'iOS'][idx % 2]}`;
    if (filters.splitDimensions.includes('归属')) row['归属'] = idx % 3 === 0 ? '自然量' : '广告量';
    if (filters.splitDimensions.includes('媒体')) row['媒体'] = filters.media.length > 0 ? filters.media[idx % filters.media.length] : (idx % 3 === 0 ? 'Organic' : 'Facebook');
    if (filters.splitDimensions.includes('Tier')) row['Tier'] = filters.tiers.length > 0 ? filters.tiers[idx % filters.tiers.length] : `T${(idx % 4) + 1}`;
    if (filters.splitDimensions.includes('国家')) row['国家'] = filters.countries.length > 0 ? filters.countries[idx % filters.countries.length] : ['US', 'CN', 'JP', 'KR', 'GB'][idx % 5];

    // 3. Basic Metrics
    const cost = Math.random() * 5000;
    const installs = Math.floor(Math.random() * 1000) + 50;
    row['花销'] = cost.toFixed(2);
    row['安装'] = installs;
    row['CPA'] = (cost / installs).toFixed(2);

    // 4. Dynamic Cohort Metrics with Realistic Trends
    filters.cohortMetrics.forEach((metric: string) => {
      // Simulate base values
      let baseValue = 0;
      if (metric.includes('留存率')) baseValue = 45; // Start at 45% retention
      else if (metric.includes('ROI')) baseValue = 5; // Start at 5% ROI
      else if (metric.includes('LTV')) baseValue = 0.5; // Start at $0.5 LTV
      else baseValue = 100;

      filters.metricDays.forEach((day: string) => {
        const d = parseInt(day);
        let val = 0;

        // Realistic progression logic
        if (metric.includes('留存率')) {
          // Retention drops over time (Logarithmic decay simulation)
          val = baseValue / (1 + Math.log(d));
        } else if (metric.includes('ROI') || metric.includes('LTV') || metric.includes('付费金额') || metric.includes('累计')) {
          // Cumulative metrics increase over time (Logarithmic growth)
          val = baseValue * (1 + Math.log(d) * 1.5);
        } else {
          // Static or random others
          val = baseValue * Math.random();
        }

        const key = `${metric} D${day}`;
        if (metric.includes('率') || metric.includes('ROI')) {
           row[key] = val.toFixed(2) + '%';
        } else {
           row[key] = val.toFixed(2);
        }
      });
    });
    return row;
  });
};

const IntegratedReport = () => {
  const [isExpanded, setIsExpanded] = useState(true);
  const [reportName, setReportName] = useState('');
  const [savedReportId, setSavedReportId] = useState<string>('');

  // Filter States
  const [timeDim, setTimeDim] = useState('daily');
  const [dateRange, setDateRange] = useState({ start: '2026-02-01', end: '2026-02-14' });
  const [project, setProject] = useState('DawnGod');
  const [games, setGames] = useState<string[]>([]);

  const [attribution, setAttribution] = useState<string>('all'); // all, ad, organic
  const [media, setMedia] = useState<string[]>([]);
  const [tiers, setTiers] = useState<string[]>([]);
  const [countries, setCountries] = useState<string[]>([]);

  const [splitDimensions, setSplitDimensions] = useState<string[]>(['游戏', '媒体']);
  const [cohortMetrics, setCohortMetrics] = useState<string[]>(['ROI', 'LTV', '留存率']);
  const [metricDays, setMetricDays] = useState<string[]>(['1', '7', '30']);

  const [reportData, setReportData] = useState<any[]>([]);
  const [generatedColumns, setGeneratedColumns] = useState<string[]>([]);

  // --- Drill-down Logic ---

  // 1. Game options based on Project
  const gameOptions = useMemo(() => {
    if (!project) return [];
    return [`${project}-Android`, `${project}-iOS`, `${project}-Huawei`, `${project}-PC`];
  }, [project]);

  // 2. Media options based on Attribution
  const mediaOptions = useMemo(() => {
    if (attribution === 'ad') return AD_CHANNELS;
    if (attribution === 'organic') return ORGANIC_CHANNELS;
    return [...AD_CHANNELS, ...ORGANIC_CHANNELS];
  }, [attribution]);

  // Reset media selection if it contains invalid options after switch
  useEffect(() => {
    setMedia(prev => prev.filter(m => mediaOptions.includes(m)));
  }, [attribution, mediaOptions]);

  // 3. Country options based on Tier
  const countryOptions = useMemo(() => {
    if (tiers.length === 0) return COUNTRY_FULL_DATA.map(c => c.iso2);
    // Unique set of ISO2 codes filtered by tier
    const filtered = COUNTRY_FULL_DATA.filter(c => tiers.includes(c.tier)).map(c => c.iso2);
    return Array.from(new Set(filtered));
  }, [tiers]);

  // Reset country selection if it contains invalid options after tier switch
  useEffect(() => {
    if (tiers.length > 0) {
      setCountries(prev => prev.filter(c => countryOptions.includes(c)));
    }
  }, [tiers, countryOptions]);

  // Helper: Get Sorted Metric Days (Numerically)
  const getSortedMetricDays = () => {
    return [...metricDays].sort((a, b) => parseInt(a) - parseInt(b));
  };

  const handleToggle = (setter: React.Dispatch<React.SetStateAction<string[]>>) => (opt: string) => {
    setter(prev => prev.includes(opt) ? prev.filter(x => x !== opt) : [...prev, opt]);
  };

  const handleQuery = () => {
    const sortedDays = getSortedMetricDays();

    // 1. Generate Columns Header
    const dims = ['日期', ...splitDimensions, '花销', '安装', 'CPA'];
    const metrics: string[] = [];

    // Generate headers in correct order: Metric A (D1, D7...), Metric B (D1, D7...)
    cohortMetrics.forEach(m => {
      sortedDays.forEach(d => {
        metrics.push(`${m} D${d}`);
      });
    });
    setGeneratedColumns([...dims, ...metrics]);

    // 2. Generate Data
    const data = generateReportData({
      timeDim, project, games, splitDimensions, cohortMetrics, 
      metricDays: sortedDays, // Pass sorted days to generator
      media, tiers, countries
    });
    setReportData(data);
  };

  // Initial load
  useEffect(() => {
    handleQuery();
  }, []);

  const renderDateInputs = () => {
    const inputClass = "h-10 px-3 bg-slate-50 border border-slate-200 rounded-lg text-sm font-bold outline-none flex-1 min-w-0";

    switch (timeDim) {
      case 'weekly':
        return (
          <>
            <input type="week" className={inputClass} value={dateRange.start} onChange={e=>setDateRange({...dateRange, start:e.target.value})} />
            <span className="self-center text-slate-400 font-bold">至</span>
            <input type="week" className={inputClass} value={dateRange.end} onChange={e=>setDateRange({...dateRange, end:e.target.value})} />
          </>
        );
      case 'monthly':
        return (
          <>
            <input type="month" className={inputClass} value={dateRange.start} onChange={e=>setDateRange({...dateRange, start:e.target.value})} />
            <span className="self-center text-slate-400 font-bold">至</span>
            <input type="month" className={inputClass} value={dateRange.end} onChange={e=>setDateRange({...dateRange, end:e.target.value})} />
          </>
        );
      case 'yearly':
        return (
          <>
            <select className={inputClass} value={dateRange.start} onChange={e=>setDateRange({...dateRange, start:e.target.value})}>
               {YEAR_OPTIONS.map(y => <option key={y} value={y}>{y}年</option>)}
            </select>
            <span className="self-center text-slate-400 font-bold">至</span>
            <select className={inputClass} value={dateRange.end} onChange={e=>setDateRange({...dateRange, end:e.target.value})}>
               {YEAR_OPTIONS.map(y => <option key={y} value={y}>{y}年</option>)}
            </select>
          </>
        );
      case 'daily':
      default:
        return (
          <>
            <input type="date" className={inputClass} value={dateRange.start} onChange={e=>setDateRange({...dateRange, start:e.target.value})} />
            <span className="self-center text-slate-400 font-bold">至</span>
            <input type="date" className={inputClass} value={dateRange.end} onChange={e=>setDateRange({...dateRange, end:e.target.value})} />
          </>
        );
    }
  };

  return (
    <div className="space-y-4 animate-in fade-in duration-500 pb-20">
      {/* --- Filter Panel --- */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden transition-all duration-300">
        {/* Header / Saved Reports Bar */}
        <div className="bg-slate-50/80 px-6 py-4 border-b border-slate-100 flex flex-wrap items-center justify-between gap-4">
          <div className="flex items-center gap-4 flex-1">
            <div className="flex items-center gap-2">
               <span className="p-2 bg-blue-100 text-blue-600 rounded-lg"><Layers size={18} /></span>
               <h2 className="font-black text-slate-800 text-lg tracking-tight">综合报表</h2>
            </div>
            <div className="h-6 w-px bg-slate-300 mx-2"></div>
            <div className="flex items-center gap-2">
               <label className="text-xs font-bold text-slate-500 uppercase">已存报表:</label>
               <select 
                 className="h-9 bg-white border border-slate-200 rounded-lg text-sm font-bold px-3 min-w-[200px] outline-none hover:border-blue-400 focus:border-blue-500 transition-colors cursor-pointer"
                 value={savedReportId}
                 onChange={(e) => setSavedReportId(e.target.value)}
               >
                 <option value="">-- 快速加载配置 --</option>
                 {SAVED_REPORTS_MOCK.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
               </select>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <div className="flex items-center gap-2 bg-white border border-slate-200 rounded-lg px-2 h-9">
