// --- Helper Functions ---

// Get Week Range: 2026-W10 -> 2026/03/02~2026/03/08
const getWeekRangeLabel = (weekStr: string) => {
  if (!weekStr.includes('-W')) return weekStr;
  const [yearStr, w] = weekStr.split('-W');
  const year = parseInt(yearStr);
  const week = parseInt(w);

  const simple = new Date(year, 0, 1 + (week - 1) * 7);
  const dow = simple.getDay();
  const ISOweekStart = simple;
  if (dow <= 4) ISOweekStart.setDate(simple.getDate() - simple.getDay() + 1);
  else ISOweekStart.setDate(simple.getDate() + 8 - simple.getDay());

  const start = new Date(ISOweekStart);
  const end = new Date(ISOweekStart);
  end.setDate(end.getDate() + 6);

  const fmt = (d: Date) => `${d.getFullYear()}/${d.getMonth()+1}/${d.getDate()}`;
  return `${fmt(start)}~${fmt(end)}`;
};

// Generate Date Array based on range and type
const generateDateSteps = (start: string, end: string, type: string) => {
  const dates = [];
  let current = new Date(start);
  const endDate = new Date(end);

  if (type === 'daily') {
    while (current <= endDate) {
      dates.push(current.toISOString().split('T')[0]);
      current.setDate(current.getDate() + 1);
    }
  } else if (type === 'weekly') {
    // Basic string comparison for weeks usually works if format is YYYY-WXX
    let currStr = start;
    while (currStr <= end) {
      dates.push(currStr);
      // Increment week logic (Simplified for mock)
      const [y, w] = currStr.split('-W').map(Number);
      let nextW = w + 1;
      let nextY = y;
      if (nextW > 52) { nextW = 1; nextY++; }
      currStr = `${nextY}-W${String(nextW).padStart(2, '0')}`;
      if (dates.length > 52) break; // Safety break
    }
  } else if (type === 'monthly') {
    let currStr = start; // 2026-02
    while (currStr <= end) {
      dates.push(currStr);
      const [y, m] = currStr.split('-').map(Number);
      let nextM = m + 1;
      let nextY = y;
      if (nextM > 12) { nextM = 1; nextY++; }
      currStr = `${nextY}-${String(nextM).padStart(2, '0')}`;
      if (dates.length > 24) break;
    }
  } else {
    // Yearly
    let currY = parseInt(start);
    const endY = parseInt(end);
    while (currY <= endY) {
      dates.push(String(currY));
      currY++;
    }
  }
  return dates;
};

// --- Mock Data Generator ---
const generateReportData = (filters: any) => {
  const rows: any[] = [];
  const dateSteps = generateDateSteps(filters.dateRange.start, filters.dateRange.end, filters.timeDim);

  let idCounter = 1;

  dateSteps.forEach(dateStep => {
    // Determine display date
    let displayDate = dateStep;
    if (filters.timeDim === 'weekly') displayDate = getWeekRangeLabel(dateStep);

    // Determine loop count based on split dimensions
    // If no split, 1 row. If split, random 2-4 rows to simulate breakdown.
    const loopCount = filters.splitDimensions.length === 0 ? 1 : Math.floor(Math.random() * 3) + 2;

    for (let i = 0; i < loopCount; i++) {
      const row: any = { id: idCounter++ };
      row['日期'] = displayDate;
      row['project_raw'] = filters.project || 'Project'; // Helper for summary

      // Dimensions
      if (filters.splitDimensions.length === 0) {
        // No Split Default Columns
        row['项目'] = filters.project || 'All';
      } else {
        // Split Logic
        if (filters.splitDimensions.includes('游戏')) row['游戏'] = filters.games.length === 1 ? filters.games[0] : `${filters.project}-${['Android', 'iOS'][i % 2]}`;
        if (filters.splitDimensions.includes('归属')) row['归属'] = i % 2 === 0 ? '广告量' : '自然量';
        if (filters.splitDimensions.includes('媒体')) row['媒体'] = filters.media.length > 0 ? filters.media[i % filters.media.length] : (i === 0 ? 'Facebook' : 'Organic');
        if (filters.splitDimensions.includes('Tier')) row['Tier'] = filters.tiers.length > 0 ? filters.tiers[i % filters.tiers.length] : `T${(i % 3) + 1}`;
        if (filters.splitDimensions.includes('国家')) row['国家'] = filters.countries.length > 0 ? filters.countries[i % filters.countries.length] : ['US', 'CN', 'GB'][i % 3];
      }

      // --- Metrics Generation (Base Values) ---
      // We generate base values first to allow accurate recalculation
      const cost = Math.random() * 2000 + 100;
      const installs = Math.floor(cost / (Math.random() * 2 + 0.5)); // CPA 0.5 - 2.5
      const registrations = Math.floor(installs * (Math.random() * 0.4 + 0.3)); // 30-70% reg rate

      // Store raw values for aggregation
      row['_cost'] = cost;
      row['_installs'] = installs;
      row['_registrations'] = registrations;

      // Display Values
      row['花销'] = cost.toFixed(2);
      row['安装'] = installs;
      row['注册'] = registrations; // Internal use or display
      row['注册率'] = ((registrations / installs) * 100).toFixed(2) + '%';
      row['CPA'] = (cost / installs).toFixed(2);

      // Cohort Metrics
      filters.cohortMetrics.forEach((metric: string) => {
        filters.metricDays.forEach((day: string) => {
          const d = parseInt(day);

          // Generate raw cohort values
          let rawVal = 0;
          if (metric.includes('留存') && !metric.includes('付费')) {
             // Retention Count
             const retentionRate = 0.5 / (1 + Math.log10(d)); // Decay
             rawVal = Math.floor(installs * retentionRate);
             row[`_val_${metric}_D${day}`] = rawVal;
             // If metric is Rate, calculate. If Count, use raw.
             if (metric.includes('率')) row[`${metric} D${day}`] = ((rawVal / installs) * 100).toFixed(2) + '%';
             else row[`${metric} D${day}`] = rawVal;

          } else if (metric.includes('ROI') || metric.includes('LTV') || metric.includes('付费金额')) {
             // Revenue based
             const ltv = 0.5 * (1 + Math.log(d));
             const revenue = installs * ltv;
             row[`_val_revenue_D${day}`] = revenue;

             if (metric.includes('付费金额') || metric.includes('总储值')) row[`${metric} D${day}`] = revenue.toFixed(2);
             if (metric.includes('LTV')) row[`${metric} D${day}`] = (revenue / installs).toFixed(2);
             if (metric.includes('ROI')) row[`${metric} D${day}`] = ((revenue / cost) * 100).toFixed(2) + '%';
          } else {
             // Others (Simulated)
             row[`${metric} D${day}`] = (Math.random() * 100).toFixed(2);
          }
        });
      });

      rows.push(row);
    }
  });

  return rows;
};

// Calculate Summary Row from Data
const calculateSummary = (data: any[], filters: any) => {
  if (data.length === 0) return null;

  const sum = (key: string) => data.reduce((acc, curr) => acc + (curr[key] || 0), 0);

  const totalCost = sum('_cost');
  const totalInstalls = sum('_installs');
  const totalRegs = sum('_registrations');

  const summary: any = {
    id: 'summary',
    '日期': '汇总',
    '项目': '-', // Or filters.project
    '花销': totalCost.toFixed(2),
    '安装': totalInstalls,
    '注册率': totalInstalls ? ((totalRegs / totalInstalls) * 100).toFixed(2) + '%' : '0.00%',
    'CPA': totalInstalls ? (totalCost / totalInstalls).toFixed(2) : '0.00',
    isSummary: true
  };

  // Fill empty split dimensions
  filters.splitDimensions.forEach((d: string) => summary[d] = '-');

  // Calculate Cohort Summaries
  filters.cohortMetrics.forEach((metric: string) => {
    filters.metricDays.forEach((day: string) => {
      const key = `${metric} D${day}`;

      if (metric.includes('留存率')) {
        // Weighted Retention Rate
        const totalRetained = sum(`_val_留存人数_D${day}`) || sum(`_val_${metric.replace('率','人数')}_D${day}`); // Try to find underlying count
        // If we generated rate directly without count in mock, we can't sum. 
        // In my generator I saved `_val_留存人数_D${day}` even if metric was Rate.
        // Let's ensure generator saves keys consistently.
        // For simplicity in mock, if key missing, average it (fallback).
        const rawKey = `_val_${metric}_D${day}`; 
        // Actually I saved `_val_留存人数_D${day}` in the loop above for '留存' types.
        // Let's assume standard lookup.
        const retentionCount = data.reduce((acc, curr) => {
            // Find hidden val
            const valKey = Object.keys(curr).find(k => k.includes(`_val`) && k.includes(`D${day}`) && k.includes('留存'));
            return acc + (curr[valKey!] || 0);
        }, 0);
        summary[key] = totalInstalls ? ((retentionCount / totalInstalls) * 100).toFixed(2) + '%' : '0.00%';

      } else if (metric.includes('ROI')) {
        const totalRevenue = data.reduce((acc, curr) => acc + (curr[`_val_revenue_D${day}`] || 0), 0);
        summary[key] = totalCost ? ((totalRevenue / totalCost) * 100).toFixed(2) + '%' : '0.00%';
      } else if (metric.includes('LTV')) {
        const totalRevenue = data.reduce((acc, curr) => acc + (curr[`_val_revenue_D${day}`] || 0), 0);
        summary[key] = totalInstalls ? (totalRevenue / totalInstalls).toFixed(2) : '0.00';
      } else if (metric.includes('付费金额') || metric.includes('人数') || metric.includes('次数')) {
         // Simple Sums for Counts/Amounts
         // We need to verify if the column displayed is a Sum or Rate. 
         // If it's a value we displayed directly, sum it? No, formatted strings.
         // Need raw values.
         // For mock simplicity: If it looks like a number, sum it.
         let val = 0;
         if (metric.includes('付费金额')) val = data.reduce((acc, curr) => acc + (curr[`_val_revenue_D${day}`] || 0), 0);
         else val = 0; // Fallback
         summary[key] = val.toFixed(2);
      }
    });
  });

  return summary;
};


