import React, { useState, useEffect, useRef } from 'react';
import { ChevronDown, Check, Search } from 'lucide-react';

interface MultiSelectDropdownProps {
  label: string;
  options: string[];
  selected: string[];
  onToggle: (opt: string) => void;
  placeholder: string;
  searchable?: boolean;
  disabledOptions?: string[];
  disabledMessage?: string;
}

const MultiSelectDropdown: React.FC<MultiSelectDropdownProps> = ({ 
  label, 
  options, 
  selected, 
  onToggle, 
  placeholder, 
  searchable = false,
  disabledOptions = [],
  disabledMessage = ''
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => { 
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setIsOpen(false); 
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    if (!isOpen) setSearchTerm('');
  }, [isOpen]);

  const filteredOptions = options.filter(opt => 
    opt.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-1.5 relative w-full" ref={containerRef}>
      <label className="text-[11px] font-bold text-slate-500 uppercase tracking-widest pl-1">{label}</label>
      <div 
        className={`w-full h-10 px-3 bg-slate-50 border rounded-lg text-sm flex items-center justify-between cursor-pointer hover:border-blue-400 transition-all shadow-sm ${isOpen ? 'border-blue-400 ring-2 ring-blue-50' : 'border-slate-200'}`}
        onClick={() => setIsOpen(!isOpen)}
      >
        <span className={`truncate ${selected.length ? 'text-blue-700 font-bold' : 'text-slate-400'} select-none`}>
          {selected.length ? `已选 ${selected.length} 项` : placeholder}
        </span>
        <ChevronDown size={14} className={`text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </div>
      {isOpen && (
        <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-slate-200 rounded-xl shadow-xl z-[1000] overflow-hidden py-1 min-w-[180px] animate-in fade-in slide-in-from-top-1 duration-200">
          {searchable && (
            <div className="px-2 py-1.5 border-b border-slate-100 bg-slate-50/50">
              <div className="relative">
                <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400"/>
                <input 
                  autoFocus
                  className="w-full pl-7 pr-2 py-1.5 text-xs border border-slate-200 rounded-md outline-none focus:border-blue-500 bg-white" 
                  placeholder="搜索..."
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                  onClick={(e) => e.stopPropagation()}
                />
              </div>
            </div>
          )}
          {/* Ensure scrollable and visible */}
          <div className="max-h-80 overflow-y-auto">
            {filteredOptions.length > 0 ? (
              filteredOptions.map(opt => {
                const isDisabled = disabledOptions.includes(opt);
                return (
                  <div 
                    key={opt} 
                    className={`px-4 py-2 flex items-center gap-3 text-sm group transition-colors ${isDisabled ? 'opacity-50 cursor-not-allowed bg-slate-50' : 'hover:bg-blue-50 cursor-pointer'}`} 
                    onClick={() => !isDisabled && onToggle(opt)}
                    title={isDisabled ? disabledMessage : ''}
                  >
                    <div className={`w-4 h-4 border rounded flex items-center justify-center transition-colors ${selected.includes(opt) ? 'bg-blue-500 border-blue-500 text-white' : 'border-slate-300 group-hover:border-blue-300'}`}>{selected.includes(opt) && <Check size={10} />}</div>
                    <span className={`truncate ${selected.includes(opt) ? 'text-blue-600 font-bold' : 'text-slate-600'}`}>{opt}</span>
                  </div>
                );
              })
            ) : (
              <div className="px-4 py-3 text-xs text-slate-400 text-center italic">无匹配项</div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default MultiSelectDropdown;

import React, { useState, useRef, useEffect } from 'react';
import { Search, RotateCcw, Download, Upload, Edit3, ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight, X, Save, Trash2, AlertCircle } from 'lucide-react';
import MultiSelectDropdown from './MultiSelectDropdown';
import { COUNTRY_FULL_DATA } from '../constants';
import { Country } from '../types';

const CountryManagement = () => {
  // Master data state to support updates/deletes
  const [masterData, setMasterData] = useState<Country[]>(COUNTRY_FULL_DATA);
  const [filteredData, setFilteredData] = useState<Country[]>(COUNTRY_FULL_DATA);

  // Search State
  const [searchParams, setSearchParams] = useState({ names: '', codes: '', iso2s: '', tiers: [] as string[] });

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 20;

  // File Upload Ref
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Edit Modal State
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Country | null>(null);

  // Helper to split comma-separated strings
  const parseSearchInput = (input: string) => {
    return input.split(/[,，]/).map(s => s.trim()).filter(s => s.length > 0);
  };

  const handleQuery = () => {
    let result = [...masterData];

    const nameKeywords = parseSearchInput(searchParams.names);
    if (nameKeywords.length > 0) {
      result = result.filter(i => nameKeywords.some(k => i.name.toLowerCase().includes(k.toLowerCase())));
    }

    const codeKeywords = parseSearchInput(searchParams.codes);
    if (codeKeywords.length > 0) {
      result = result.filter(i => codeKeywords.some(k => i.code.toLowerCase().includes(k.toLowerCase())));
    }

    const iso2Keywords = parseSearchInput(searchParams.iso2s);
    if (iso2Keywords.length > 0) {
      result = result.filter(i => iso2Keywords.some(k => i.iso2.toLowerCase().includes(k.toLowerCase())));
    }

    if (searchParams.tiers.length > 0) {
      result = result.filter(i => searchParams.tiers.includes(i.tier));
    }

    setFilteredData(result); 
    setCurrentPage(1);
  };

  const handleReset = () => {
    setSearchParams({names:'', codes:'', iso2s:'', tiers:[]});
    setFilteredData(masterData);
    setCurrentPage(1);
  };

  // Upload Handling
  const handleUploadClick = () => {
    if (fileInputRef.current) {
      fileInputRef.current.value = ''; // Reset
      fileInputRef.current.click();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const validExtensions = ['.xlsx', '.xls', '.csv'];
    const fileName = file.name.toLowerCase();
    const isValid = validExtensions.some(ext => fileName.endsWith(ext));

    if (!isValid) {
      alert("上传的格式不对，录入失败。");
      return;
    }

    // Mock success
    alert(`文件 "${file.name}" 上传成功，数据已进入处理队列。`);
  };

  const handleDownload = () => {
    const csvContent = "\ufeff国家,地区码,二字码,tier\n";
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.setAttribute('download', '国家导入模板.csv');
    document.body.appendChild(link); link.click(); document.body.removeChild(link);
  };

  // Edit Modal Handling
  const openEditModal = (item: Country) => {
    setEditingItem({ ...item }); // Clone to avoid direct mutation
    setIsEditModalOpen(true);
  };

  const handleSaveEdit = () => {
    if (!editingItem) return;

    // Update Master Data
    const updatedMaster = masterData.map(item => item.id === editingItem.id ? editingItem : item);
    setMasterData(updatedMaster);

    // Update Filtered Data (keep current filter context if possible, or just update row)
    const updatedFiltered = filteredData.map(item => item.id === editingItem.id ? editingItem : item);
    setFilteredData(updatedFiltered);

    setIsEditModalOpen(false);
    setEditingItem(null);
  };

  const handleDeleteItem = () => {
    if (!editingItem) return;
    if (window.confirm(`确定要删除 ${editingItem.name} 吗？`)) {
      const updatedMaster = masterData.filter(item => item.id !== editingItem.id);
      setMasterData(updatedMaster);

      const updatedFiltered = filteredData.filter(item => item.id !== editingItem.id);
      setFilteredData(updatedFiltered);

      setIsEditModalOpen(false);
      setEditingItem(null);
    }
  };

  const totalPages = Math.ceil(filteredData.length / pageSize);
  const currentData = filteredData.slice((currentPage - 1) * pageSize, currentPage * pageSize);

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10 relative">
      <section className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 items-end">
          <div className="space-y-1.5">
            <label className="text-[11px] font-bold text-slate-500 uppercase pl-1">国家/地区名 (支持多选)</label>
            <input type="text" placeholder="输入名称, 用逗号分隔" className="w-full h-10 px-3 bg-slate-50 border rounded-lg text-sm" value={searchParams.names} onChange={e=>setSearchParams({...searchParams, names:e.target.value})} />
          </div>
          <div className="space-y-1.5">
            <label className="text-[11px] font-bold text-slate-500 uppercase pl-1">地区码 (支持多选)</label>
            <input type="text" placeholder="如: CHN, USA" className="w-full h-10 px-3 bg-slate-50 border rounded-lg text-sm" value={searchParams.codes} onChange={e=>setSearchParams({...searchParams, codes:e.target.value})} />
          </div>
          <div className="space-y-1.5">
            <label className="text-[11px] font-bold text-slate-500 uppercase pl-1">二字码 (支持多选)</label>
            <input type="text" placeholder="如: CN, US" className="w-full h-10 px-3 bg-slate-50 border rounded-lg text-sm" value={searchParams.iso2s} onChange={e=>setSearchParams({...searchParams, iso2s:e.target.value})} />
          </div>
          <MultiSelectDropdown label="Tier 分类" options={['T1', 'T2', 'T3', 'T4']} selected={searchParams.tiers} onToggle={opt => setSearchParams(prev => ({...prev, tiers: prev.tiers.includes(opt)?prev.tiers.filter(x=>x!==opt):[...prev.tiers, opt]}))} placeholder="选择 Tier" />
        </div>
        <div className="flex justify-end gap-3 pt-6 border-t mt-4">
          <button onClick={handleReset} className="h-10 px-6 font-bold text-slate-500 bg-slate-100 rounded-lg flex items-center gap-2 hover:bg-slate-200 transition-colors"><RotateCcw size={16}/> 重置</button>
          <button onClick={handleQuery} className="h-10 px-10 font-bold bg-blue-600 text-white rounded-lg shadow-md hover:bg-blue-700 transition-all flex items-center gap-2 active:scale-95"><Search size={16}/> 查询</button>
        </div>
      </section>

      <section className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
        <div className="p-4 border-b bg-slate-50/50 flex justify-between items-center">
          <span className="text-[11px] font-black text-slate-500 uppercase px-3 italic">Master Data View ({filteredData.length})</span>
          <div className="flex gap-2">
            <button onClick={handleDownload} className="h-9 px-4 text-xs font-bold text-slate-600 bg-white border rounded-lg flex items-center gap-2 shadow-sm hover:bg-slate-50 transition-colors"><Download size={14}/> 下载模板</button>
            <button onClick={handleUploadClick} className="h-9 px-4 text-xs font-bold text-white bg-blue-600 rounded-lg flex items-center gap-2 hover:bg-blue-700 transition-colors shadow-md active:scale-95">
              <Upload size={14}/> 批量上传
            </button>
            {/* Hidden File Input */}
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept=".csv,.xlsx,.xls" 
              onChange={handleFileChange} 
            />
          </div>
        </div>
        <div className="overflow-x-auto min-h-[400px]">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/80 text-slate-400 text-[10px] uppercase font-black border-b h-14">
                <th className="px-6 py-4">ID</th><th className="px-6 py-4">国家/地区</th><th className="px-6 py-4">地区码</th><th className="px-6 py-4">二字码</th><th className="px-6 text-center">Tier</th><th className="px-6 text-center">本地货币</th><th className="px-6 text-center">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {currentData.map(item => (
                <tr key={item.id} className="hover:bg-blue-50/10 transition-colors h-14">
                  <td className="px-6 text-xs font-mono text-slate-400">{item.id}</td><td className="px-6 text-sm font-bold text-slate-800">{item.name}</td>
                  <td className="px-6 text-sm font-mono text-slate-500">{item.code}</td><td className="px-6 text-sm font-mono text-slate-500">{item.iso2}</td>
                  <td className="px-6 text-center"><span className={`px-3 py-1 rounded-md text-[10px] font-black uppercase shadow-sm ${item.tier === 'T1' ? 'bg-indigo-500 text-white' : item.tier === 'T2' ? 'bg-blue-500 text-white' : 'bg-emerald-500 text-white'}`}>{item.tier}</span></td>
                  <td className="px-6 text-xs font-bold text-slate-500 text-center uppercase tracking-tight">{item.currency}</td>
                  <td className="px-6 text-center"><button onClick={() => openEditModal(item)} className="p-2 text-blue-500 hover:bg-blue-100 rounded-lg transition-all"><Edit3 size={15}/></button></td>
                </tr>
              ))}
              {currentData.length === 0 && (
                <tr>
                  <td colSpan={7} className="text-center py-20 text-slate-300 font-bold uppercase tracking-widest">No Data Found</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
        {/* Pagination Controls */}
        <div className="p-4 border-t bg-slate-50/30 flex items-center justify-between">
          <div className="text-xs text-slate-400 font-bold">
            Showing <span className="text-slate-700">{filteredData.length > 0 ? (currentPage - 1) * pageSize + 1 : 0}</span> to <span className="text-slate-700">{Math.min(currentPage * pageSize, filteredData.length)}</span> of <span className="text-slate-700">{filteredData.length}</span> results
          </div>
          <div className="flex gap-1.5 items-center">
             <button 
               onClick={() => setCurrentPage(1)} disabled={currentPage === 1}
               className="w-8 h-8 flex items-center justify-center rounded-lg border bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed text-slate-500"
             >
               <ChevronsLeft size={14} />
             </button>
             <button 
               onClick={() => setCurrentPage(c => Math.max(1, c - 1))} disabled={currentPage === 1}
               className="w-8 h-8 flex items-center justify-center rounded-lg border bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed text-slate-500"
             >
               <ChevronLeft size={14} />
             </button>

             <div className="px-3 text-xs font-bold text-slate-600">
               Page {currentPage} of {Math.max(1, totalPages)}
             </div>

             <button 
               onClick={() => setCurrentPage(c => Math.min(totalPages, c + 1))} disabled={currentPage === totalPages || totalPages === 0}
               className="w-8 h-8 flex items-center justify-center rounded-lg border bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed text-slate-500"
             >
               <ChevronRight size={14} />
             </button>
             <button 
               onClick={() => setCurrentPage(totalPages)} disabled={currentPage === totalPages || totalPages === 0}
               className="w-8 h-8 flex items-center justify-center rounded-lg border bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed text-slate-500"
             >
               <ChevronsRight size={14} />
             </button>
          </div>
        </div>
      </section>

      {/* Edit Modal */}
      {isEditModalOpen && editingItem && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in duration-300 flex flex-col">
            <div className="px-6 py-4 border-b bg-slate-50/50 flex justify-between items-center">
              <div className="flex items-center gap-2">
                <Edit3 size={18} className="text-blue-600" />
                <h3 className="font-black text-slate-800 uppercase text-sm tracking-wide">编辑国家配置</h3>
              </div>
              <button onClick={() => setIsEditModalOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-all text-slate-400 hover:text-slate-600">
                <X size={20}/>
              </button>
            </div>

            <div className="p-8 space-y-6">
               <div className="space-y-4">
                 <div className="grid grid-cols-2 gap-4">
                   <div className="space-y-1.5">
                     <label className="text-[10px] font-black text-slate-400 uppercase">ID (不可变)</label>
                     <input type="text" disabled value={editingItem.id} className="w-full h-10 px-3 border border-slate-200 rounded-lg text-sm bg-slate-100 text-slate-400 cursor-not-allowed" />
                   </div>
                   <div className="space-y-1.5">
                     <label className="text-[10px] font-black text-slate-500 uppercase">Tier 级别</label>
                     <select 
                       value={editingItem.tier}
                       onChange={(e) => setEditingItem({...editingItem, tier: e.target.value})}
                       className="w-full h-10 px-3 border border-slate-200 rounded-lg text-sm font-bold bg-white focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all"
                     >
                       {['T1', 'T2', 'T3', 'T4'].map(t => <option key={t} value={t}>{t}</option>)}
                     </select>
                   </div>
                 </div>

                 <div className="space-y-1.5">
                   <label className="text-[10px] font-black text-slate-500 uppercase">国家/地区名称</label>
                   <input 
                     type="text" 
                     value={editingItem.name} 
                     onChange={(e) => setEditingItem({...editingItem, name: e.target.value})}
                     className="w-full h-10 px-3 border border-slate-200 rounded-lg text-sm font-bold focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all"
                   />
                 </div>

                 <div className="grid grid-cols-2 gap-4">
                   <div className="space-y-1.5">
                     <label className="text-[10px] font-black text-slate-500 uppercase">地区三字码</label>
                     <input 
                       type="text" 
                       value={editingItem.code} 
                       onChange={(e) => setEditingItem({...editingItem, code: e.target.value})}
                       className="w-full h-10 px-3 border border-slate-200 rounded-lg text-sm font-bold focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all uppercase"
                     />
                   </div>
                   <div className="space-y-1.5">
                     <label className="text-[10px] font-black text-slate-500 uppercase">地区二字码</label>
                     <input 
                       type="text" 
                       value={editingItem.iso2} 
                       onChange={(e) => setEditingItem({...editingItem, iso2: e.target.value})}
                       className="w-full h-10 px-3 border border-slate-200 rounded-lg text-sm font-bold focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all uppercase"
                     />
                   </div>
                 </div>

                 <div className="space-y-1.5">
                   <label className="text-[10px] font-black text-slate-500 uppercase">本地货币</label>
                   <input 
                     type="text" 
                     value={editingItem.currency} 
                     onChange={(e) => setEditingItem({...editingItem, currency: e.target.value})}
                     className="w-full h-10 px-3 border border-slate-200 rounded-lg text-sm font-bold focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all uppercase"
                   />
                 </div>
               </div>
            </div>

            <div className="px-8 py-5 bg-slate-50 border-t flex justify-between items-center">
              <button 
                onClick={handleDeleteItem}
                className="text-xs font-black text-red-500 hover:text-red-700 flex items-center gap-1.5 px-3 py-2 rounded-lg hover:bg-red-50 transition-colors"
              >
                <Trash2 size={14} /> 删除该国家
              </button>
              <div className="flex gap-3">
                <button onClick={() => setIsEditModalOpen(false)} className="px-5 py-2.5 font-bold text-slate-500 text-xs hover:text-slate-700">取消</button>
                <button onClick={handleSaveEdit} className="px-8 py-2.5 bg-blue-600 text-white font-black text-xs rounded-xl shadow-lg hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
                  <Save size={14} /> 保存更改
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CountryManagement;

import React, { useState, useMemo, useRef } from 'react';
import { Plus, Trash2, Download, Check, Edit3, Upload, X, Save, AlertCircle } from 'lucide-react';
import MultiSelectDropdown from './MultiSelectDropdown';
import { INITIAL_COST_DATA, PROJECTS, SYSTEM_CHANNELS, REGIONS } from '../constants';
import { CostRecord } from '../types';

const CostManagement = () => {
  const [data, setData] = useState<CostRecord[]>(INITIAL_COST_DATA);
  const [filteredData, setFilteredData] = useState<CostRecord[]>(INITIAL_COST_DATA);
  const [selectedIds, setSelectedIds] = useState<number[]>([]);
  const [filters, setFilters] = useState({ startDate: '', endDate: '', project: '', games: [] as string[], media: [] as string[] });

  // Upload Ref
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Modals
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  // Create State
  const [newCostRows, setNewCostRows] = useState<Partial<CostRecord>[]>([
    { date: new Date().toISOString().split('T')[0], currency: 'USD', operator: '邓文豪', isSystem: false }
  ]);

  // Edit State
  const [editingItem, setEditingItem] = useState<CostRecord | null>(null);

  const gameOptions = useMemo(() => filters.project ? [`${filters.project}-Android`, `${filters.project}-iOS`, `${filters.project}-Huawei`] : [], [filters.project]);

  const handleQuery = () => {
    let result = [...data];
    if (filters.startDate) result = result.filter(i => i.date >= filters.startDate);
    if (filters.endDate) result = result.filter(i => i.date <= filters.endDate);
    if (filters.project) result = result.filter(i => i.projectName === (filters.project === 'DawnGod' ? 'Dawn God' : 'Fruit'));
    if (filters.games.length > 0) result = result.filter(i => filters.games.includes(i.gameName));
    if (filters.media.length > 0) result = result.filter(i => filters.media.includes(i.media));
    setFilteredData(result); 
    setSelectedIds([]);
  };

  const handleDownload = () => {
    const csv = "\ufeff日期,项目名称,游戏名称,媒体,地区,广告系列,花费金额,货币\n";
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob); link.download = '花费模板.csv'; 
    document.body.appendChild(link); link.click(); document.body.removeChild(link);
  };

  // Upload Handling
  const handleUploadClick = () => {
    if (fileInputRef.current) {
      fileInputRef.current.value = ''; 
      fileInputRef.current.click();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const validExtensions = ['.xlsx', '.xls', '.csv'];
    if (!validExtensions.some(ext => file.name.toLowerCase().endsWith(ext))) {
      alert("上传的格式不对，录入失败。");
      return;
    }
    alert(`文件 "${file.name}" 上传成功，数据已进入处理队列。`);
  };

  // Create Logic
  const handleAddRow = () => {
    setNewCostRows([...newCostRows, { date: new Date().toISOString().split('T')[0], currency: 'USD', operator: '邓文豪', isSystem: false }]);
  };

  const handleRemoveRow = (index: number) => {
    if (newCostRows.length > 1) {
      setNewCostRows(newCostRows.filter((_, i) => i !== index));
    }
  };

  const handleRowChange = (index: number, field: keyof CostRecord, value: any) => {
    const updated = [...newCostRows];
    updated[index] = { ...updated[index], [field]: value };
    // Auto-fill game if project changes (Mock logic)
    if (field === 'projectName') {
       updated[index].gameName = ''; // Reset game
    }
    setNewCostRows(updated);
  };

  const handleSubmitCreate = () => {
    // Basic validation
    if (newCostRows.some(r => !r.projectName || !r.gameName || !r.media || !r.cost)) {
        alert("请完善所有必填字段 (项目, 游戏, 媒体, 金额)");
        return;
    }

    const newRecords = newCostRows.map((row, idx) => ({
        ...row,
        id: Math.max(...data.map(d => d.id), 0) + 1 + idx,
        cost: Number(row.cost).toFixed(2),
        region: row.region || 'Global' // Default region if missed
    } as CostRecord));

    const updatedData = [...newRecords, ...data].sort((a,b) => b.date.localeCompare(a.date)); // Newest first
    setData(updatedData);
    setFilteredData(updatedData); // Reset view to show new data
    setIsCreateModalOpen(false);
    setNewCostRows([{ date: new Date().toISOString().split('T')[0], currency: 'USD', operator: '邓文豪', isSystem: false }]);
  };

  // Edit Logic
  const openEditModal = (item: CostRecord) => {
    setEditingItem({...item});
    setIsEditModalOpen(true);
  };

  const handleSaveEdit = () => {
    if (!editingItem) return;
    const updatedData = data.map(d => d.id === editingItem.id ? editingItem : d);
    setData(updatedData);

    // Update filtered data as well to reflect changes immediately
    const updatedFiltered = filteredData.map(d => d.id === editingItem.id ? editingItem : d);
    setFilteredData(updatedFiltered);

    setIsEditModalOpen(false);
    setEditingItem(null);
  };

  const handleDeleteEdit = () => {
    if (!editingItem) return;
    if (window.confirm("确认删除这条花费记录吗？")) {
        const updatedData = data.filter(d => d.id !== editingItem.id);
        setData(updatedData);
        setFilteredData(filteredData.filter(d => d.id !== editingItem.id));
        setIsEditModalOpen(false);
        setEditingItem(null);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
      <section className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-5 gap-6 items-end">
          <div className="space-y-1 flex flex-col"><label className="text-[11px] font-bold text-slate-500 uppercase tracking-widest pl-1">时间范围</label>
            <div className="grid grid-cols-2 gap-2 h-10"><input type="date" className="w-full px-2 bg-slate-50 border rounded-lg text-xs outline-none" value={filters.startDate} onChange={e=>setFilters({...filters, startDate:e.target.value})} /><input type="date" className="w-full px-2 bg-slate-50 border rounded-lg text-xs outline-none" value={filters.endDate} onChange={e=>setFilters({...filters, endDate:e.target.value})} /></div>
          </div>
          <div className="space-y-1.5"><label className="text-[11px] font-bold text-slate-500 uppercase tracking-widest pl-1">项目</label>
            <select className="w-full h-10 px-3 bg-slate-50 border rounded-lg text-sm font-bold shadow-sm outline-none" value={filters.project} onChange={e=>setFilters({...filters, project: e.target.value, games: []})}><option value="">全部项目</option>{PROJECTS.map(p => <option key={p} value={p}>{p}</option>)}</select>
          </div>
          <MultiSelectDropdown label="游戏名称 (钻取多选)" options={gameOptions} selected={filters.games} onToggle={opt=>setFilters(prev=>({...prev, games: prev.games.includes(opt)?prev.games.filter(x=>x!==opt):[...prev.games, opt]}))} placeholder={filters.project ? "选择名称" : "先选项目"} />
          <MultiSelectDropdown label="媒体多选" options={[...SYSTEM_CHANNELS, 'ASA']} selected={filters.media} onToggle={opt=>setFilters(prev=>({...prev, media: prev.media.includes(opt)?prev.media.filter(x=>x!==opt):[...prev.media, opt]}))} placeholder="选择媒体" />
          <div className="flex gap-2 h-10"><button onClick={()=>{setFilters({startDate:'', endDate:'', project:'', games:[], media:[]}); setFilteredData(data);}} className="flex-1 font-bold bg-slate-100 rounded-lg hover:bg-slate-200">重置</button><button onClick={handleQuery} className="flex-[1.5] font-bold bg-blue-600 text-white rounded-lg shadow-md active:scale-95 transition-all hover:bg-blue-700">查询</button></div>
        </div>
      </section>

      <div className="flex items-center justify-between">
        <div className="flex gap-3">
            <button onClick={() => setIsCreateModalOpen(true)} className="h-10 px-6 bg-blue-600 text-white text-sm font-black rounded-xl shadow-md flex items-center gap-2 hover:bg-blue-700 active:scale-95 transition-all"><Plus size={18}/> 新增花费</button>
            <button disabled={selectedIds.length === 0} onClick={()=>{setData(data.filter(i=>!selectedIds.includes(i.id))); setFilteredData(filteredData.filter(i=>!selectedIds.includes(i.id))); setSelectedIds([]);}} className={`h-10 px-5 text-sm font-bold rounded-xl flex items-center gap-2 ${selectedIds.length > 0 ? 'bg-red-50 text-red-600 border border-red-200 hover:bg-red-100' : 'bg-slate-100 text-slate-300'}`}><Trash2 size={16}/> 批量删除 ({selectedIds.length})</button>
        </div>
        <div className="flex gap-2">
            <button onClick={handleDownload} className="h-9 px-4 text-xs font-bold text-slate-600 bg-white border rounded-lg flex items-center gap-2 shadow-sm transition-all hover:bg-slate-50"><Download size={14}/> 下载模板</button>
            <button onClick={handleUploadClick} className="h-9 px-4 text-xs font-bold text-white bg-emerald-600 rounded-lg shadow-md flex items-center gap-2 active:scale-95 transition-all hover:bg-emerald-700">
                <Upload size={14}/> 批量上传
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept=".csv,.xlsx,.xls" onChange={handleFileChange} />
        </div>
      </div>

      <section className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[400px]">
        <div className="overflow-x-auto flex-1">
          <table className="w-full text-left border-collapse min-w-[1100px]">
            <thead>
              <tr className="bg-slate-50/80 text-slate-400 text-[9px] uppercase tracking-widest font-black border-b h-14">
                <th className="px-5 w-12 text-center sticky left-0 bg-slate-50 z-10"><div className="w-4 h-4 border rounded mx-auto cursor-pointer" onClick={() => {const pageIds = filteredData.slice(0, 20).filter(i=>!i.isSystem).map(i=>i.id); setSelectedIds(selectedIds.length === pageIds.length ? [] : pageIds);}}></div></th>
                <th className="px-5">日期</th><th className="px-5">项目</th><th className="px-5">游戏名称</th><th className="px-5">媒体</th><th className="px-5 text-right">金额</th><th className="px-5">操作者</th><th className="px-5 text-center sticky right-0 bg-slate-50/90 border-l">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 font-medium">
              {filteredData.slice(0, 50).map(item => (
                <tr key={item.id} className={`h-14 transition-colors ${item.isSystem ? 'bg-slate-50/30' : 'hover:bg-blue-50/10'}`}>
                  <td className="px-5 text-center sticky left-0 bg-white">{!item.isSystem && <div className={`w-4 h-4 border rounded mx-auto cursor-pointer transition-colors ${selectedIds.includes(item.id) ? 'bg-blue-600 border-blue-600' : 'bg-white'}`} onClick={() => setSelectedIds(prev => prev.includes(item.id) ? prev.filter(i=>i!==item.id) : [...prev, item.id])}>{selectedIds.includes(item.id) && <Check className="text-white mx-auto" size={10}/>}</div>}</td>
                  <td className="px-5 text-xs font-mono">{item.date}</td><td className="px-5 text-xs font-black uppercase text-slate-800">{item.projectName}</td><td className="px-5 text-xs font-bold text-slate-500">{item.gameName}</td>
                  <td className="px-5"><span className={`px-2.5 py-1 rounded text-[10px] font-black uppercase ${item.media === 'ASA' ? 'bg-orange-50 text-orange-600' : 'bg-slate-50 text-slate-400'}`}>{item.media}</span></td>
                  <td className="px-5 text-xs font-black text-blue-600 text-right">${item.cost}</td><td className="px-5 text-[10px] font-bold text-slate-400 italic">{item.operator}</td>
                  <td className="px-5 text-center sticky right-0 bg-white border-l transition-colors group-hover:bg-blue-50">
                    <button disabled={item.isSystem} onClick={() => openEditModal(item)} className={`p-2 rounded-lg transition-colors ${item.isSystem ? 'text-slate-200 cursor-not-allowed' : 'text-blue-500 hover:bg-blue-100'}`}><Edit3 size={15}/></button>
                  </td>
                </tr>
              ))}
              {filteredData.length === 0 && <tr><td colSpan={8} className="text-center py-20 text-slate-300">No records found</td></tr>}
            </tbody>
          </table>
        </div>
      </section>

      {/* --- Create Modal --- */}
      {isCreateModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden animate-in zoom-in duration-300 flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b bg-slate-50/50 flex justify-between items-center">
              <h3 className="font-black text-slate-800 uppercase text-sm tracking-wide flex items-center gap-2"><Plus size={18} className="text-blue-600"/> 批量录入花费</h3>
              <button onClick={() => setIsCreateModalOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-all text-slate-400"><X size={20}/></button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 bg-slate-50/30">
               <table className="w-full text-left border-collapse">
                 <thead>
                   <tr className="text-[10px] font-black uppercase text-slate-400 border-b">
                     <th className="px-3 py-2 w-12">#</th>
                     <th className="px-3 py-2 w-40">日期</th>
                     <th className="px-3 py-2 w-40">项目</th>
                     <th className="px-3 py-2 w-48">游戏名称</th>
                     <th className="px-3 py-2 w-32">媒体</th>
                     <th className="px-3 py-2 w-24">地区</th>
                     <th className="px-3 py-2 w-32">金额 (USD)</th>
                     <th className="px-3 py-2 w-16"></th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100 bg-white">
                   {newCostRows.map((row, idx) => {
                     const rowProject = row.projectName || '';
