                        {[...SYSTEM_CHANNELS, 'ASA'].map(m => <option key={m} value={m}>{m}</option>)}
                     </select>
                  </div>
                  <div className="space-y-1.5">
                     <label className="text-[10px] font-black text-slate-400 uppercase">金额 (USD)</label>
