import { CustomTier } from '../types';

// --- Types ---
type ChartType = 'line' | 'bar' | 'area' | 'pie' | 'number';
type CardSize = 'small' | 'medium' | 'large' | 'full';

interface ChartConfig {
  id: string;
  type: ChartType;
  title: string;
  metric: string; 
  metricDay?: string; // For cohort metrics (e.g., '1', '7', '30')
  dimension: string;
  size: CardSize;
}

const METRICS = [
  { value: 'cost', label: '花销 (Cost)', hasDays: false },
  { value: 'installs', label: '安装数 (Installs)', hasDays: false },
  { value: 'cpa', label: 'CPA', hasDays: false },
  { value: 'roi', label: 'ROI', hasDays: true },
  { value: 'ltv', label: 'LTV', hasDays: true },
  { value: 'retention', label: '留存率 (Retention)', hasDays: true },
  { value: 'revenue', label: '收入 (Revenue)', hasDays: false }
];

const METRIC_DAYS = ['1', '3', '7', '14', '30', '60', '90', '180'];

const DIMENSIONS = [
  { value: 'date', label: '时间 (Date)' },
  { value: 'country', label: '国家 (Country)' },
  { value: 'media', label: '媒体 (Media)' },
  { value: 'project', label: '项目 (Project)' }
];

const CHART_TYPES = [
  { type: 'line', label: '折线图', icon: LineChart, desc: '趋势分析' },
  { type: 'area', label: '面积图', icon: AreaChartIcon, desc: '堆积趋势' },
  { type: 'bar', label: '柱状图', icon: BarChart3, desc: '对比分析' },
  { type: 'pie', label: '饼状图', icon: PieChart, desc: '占比分布' },
  { type: 'number', label: '指标卡', icon: TrendingUp, desc: '关键数据' }
];

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

// --- Data Generator ---
const generateChartData = (config: ChartConfig, dateRange: {start: string, end: string}) => {
  const data = [];
  const isDateDim = config.dimension === 'date';
  const count = isDateDim ? 7 : 5; // 7 days or 5 categories

  for (let i = 0; i < count; i++) {
    let name = '';
    if (config.dimension === 'date') {
        const d = new Date(dateRange.start);
        d.setDate(d.getDate() + i);
        name = d.toISOString().slice(5, 10);
    } else if (config.dimension === 'country') {
        name = ['US', 'JP', 'KR', 'DE', 'GB'][i];
    } else if (config.dimension === 'media') {
        name = ['Facebook', 'Google', 'TikTok', 'Unity', 'Applovin'][i];
    } else {
        name = `Item ${i+1}`;
    }

    // Mock Values based on metric type
    let value = 0;
    if (config.metric === 'cost') value = Math.floor(Math.random() * 5000) + 1000;
    else if (config.metric === 'roi') value = parseFloat((Math.random() * 1.5).toFixed(2)); // 0.00 - 1.50
    else if (config.metric === 'retention') value = parseFloat((Math.random() * 50).toFixed(2)); // 0 - 50%
    else value = Math.floor(Math.random() * 1000);

    data.push({ name, value });
  }
  return data;
};

// --- Main Component ---

const DataDashboard = () => {
  // Filter States
  const [timeRange, setTimeRange] = useState({ start: '2026-02-01', end: '2026-02-07' });
  const [filters, setFilters] = useState({
    project: 'DawnGod',
    games: [] as string[],
    media: [] as string[],
    tiers: [] as string[],
    countries: [] as string[]
  });

  // Dashboard Data
  const [charts, setCharts] = useState<ChartConfig[]>([]);
  const [dashboardName, setDashboardName] = useState('My Marketing Dashboard');

  // Modal & Edit State
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [editingChartId, setEditingChartId] = useState<string | null>(null); // If set, we are editing this chart
  const [chartConfigForm, setChartConfigForm] = useState<Partial<ChartConfig>>({ 
    type: 'line', metric: 'cost', metricDay: '7', dimension: 'date', size: 'medium' 
  });

  // Custom Tier Logic
  const [customTiers, setCustomTiers] = useState<CustomTier[]>([]);
  useEffect(() => {
    const stored = localStorage.getItem('custom_tiers');
    if (stored) setCustomTiers(JSON.parse(stored));

    const storedDash = localStorage.getItem('my_dashboard_v2');
    if (storedDash) {
        try {
            const parsed = JSON.parse(storedDash);
            setCharts(parsed.charts || []);
            setDashboardName(parsed.name || 'My Dashboard');
        } catch(e) {}
    } else {
        // Default Charts
        setCharts([
            { id: '1', type: 'area', title: '近7日花费趋势', metric: 'cost', dimension: 'date', size: 'large' },
            { id: '2', type: 'bar', title: '各国家 ROI (D7) 对比', metric: 'roi', metricDay: '7', dimension: 'country', size: 'medium' },
            { id: '3', type: 'pie', title: '媒体花费占比', metric: 'cost', dimension: 'media', size: 'small' }
        ]);
    }
  }, []);

  const tierOptions = useMemo(() => ['T1', 'T2', 'T3', 'T4', ...customTiers.map(t => t.name)], [customTiers]);
  const gameOptions = useMemo(() => filters.project ? [`${filters.project}-Android`, `${filters.project}-iOS`] : [], [filters.project]);
  const countryOptions = useMemo(() => COUNTRY_FULL_DATA.map(c => c.iso2), []);
  const mediaOptions = ['Facebook', 'Google Ads', 'TikTok', 'Unity', 'Applovin', 'IronSource'];

  // Handlers
  const handleSaveDashboard = () => {
    const dashData = { name: dashboardName, charts };
    localStorage.setItem('my_dashboard_v2', JSON.stringify(dashData));
    alert("仪表盘布局已保存 (Dashboard Saved)");
  };

  const handleOpenAdd = () => {
      setEditingChartId(null);
      setChartConfigForm({ type: 'line', metric: 'cost', metricDay: '7', dimension: 'date', size: 'medium', title: '' });
      setIsAddModalOpen(true);
  };

  const handleOpenEdit = (chart: ChartConfig) => {
      setEditingChartId(chart.id);
      setChartConfigForm({ ...chart });
      setIsAddModalOpen(true);
  };

  const handleSaveChartConfig = () => {
    // Generate Title if empty
    let title = chartConfigForm.title;
    if (!title) {
       const mObj = METRICS.find(m => m.value === chartConfigForm.metric);
       const dLabel = DIMENSIONS.find(d => d.value === chartConfigForm.dimension)?.label.split(' ')[0];
       const mLabel = mObj?.label.split(' ')[0];
       const daySuffix = mObj?.hasDays ? ` (D${chartConfigForm.metricDay})` : '';
       title = `${dLabel} - ${mLabel}${daySuffix}`;
    }

    const newConfig: ChartConfig = {
        id: editingChartId || Date.now().toString(),
        type: chartConfigForm.type || 'line',
        title: title,
        metric: chartConfigForm.metric || 'cost',
        metricDay: chartConfigForm.metricDay,
        dimension: chartConfigForm.dimension || 'date',
        size: chartConfigForm.size || 'medium'
    };

    if (editingChartId) {
        setCharts(charts.map(c => c.id === editingChartId ? newConfig : c));
    } else {
        setCharts([...charts, newConfig]);
    }
    setIsAddModalOpen(false);
  };

  const removeChart = (id: string) => {
      if(window.confirm('确定移除此图表吗？')) {
        setCharts(charts.filter(c => c.id !== id));
      }
  };

  // Helper to determine Grid Column Span
  const getColSpan = (size: CardSize) => {
      switch(size) {
          case 'small': return 'col-span-1';
          case 'medium': return 'col-span-1 md:col-span-2';
          case 'large': return 'col-span-1 md:col-span-2 lg:col-span-3';
          case 'full': return 'col-span-1 md:col-span-2 lg:col-span-4';
          default: return 'col-span-1 md:col-span-2';
      }
  };

  // --- Render Chart Content using Recharts ---
  const renderChartContent = (chart: ChartConfig) => {
    const data = generateChartData(chart, timeRange);
    const mObj = METRICS.find(m => m.value === chart.metric);
    const isPercent = chart.metric === 'roi' || chart.metric === 'retention';
    const valueFormatter = (val: number) => isPercent ? `${val}%` : val.toLocaleString();

    if (chart.type === 'number') {
        const total = data.reduce((acc, cur) => acc + cur.value, 0);
        return (
            <div className="flex flex-col items-center justify-center h-full pb-4">
                <span className="text-5xl font-black text-slate-800 tracking-tighter">{valueFormatter(total)}</span>
                <span className="text-xs font-bold text-slate-400 uppercase mt-2 tracking-widest">{chart.title}</span>
                <div className="flex gap-2 mt-4">
                    <span className="text-[10px] text-emerald-600 font-bold bg-emerald-50 px-2 py-0.5 rounded-full">▲ 12.5% vs period</span>
                </div>
            </div>
        );
    }

    return (
        <ResponsiveContainer width="100%" height="100%">
            {chart.type === 'pie' ? (
                <RePieChart>
                    <Pie 
                        data={data} 
                        cx="50%" cy="50%" 
                        innerRadius={60} 
                        outerRadius={80} 
                        paddingAngle={5} 
                        dataKey="value"
                    >
                        {data.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                    </Pie>
                    <Tooltip formatter={valueFormatter} />
                    <Legend verticalAlign="bottom" height={36} iconType="circle" />
                </RePieChart>
            ) : chart.type === 'line' ? (
                <ReLineChart data={data} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} dy={10} />
                    <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} tickFormatter={valueFormatter} />
                    <Tooltip 
                        contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} 
                        formatter={(value: number) => [valueFormatter(value), chart.metric.toUpperCase()]}
                    />
                    <Legend verticalAlign="top" height={36} iconType="plainline" />
                    <Line type="monotone" dataKey="value" stroke="#3b82f6" strokeWidth={3} dot={{r: 4, fill: '#3b82f6', strokeWidth: 2, stroke: '#fff'}} activeDot={{r: 6}} name={chart.metric} />
                </ReLineChart>
            ) : chart.type === 'area' ? (
                <ReAreaChart data={data} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                    <defs>
                        <linearGradient id={`color${chart.id}`} x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#8b5cf6" stopOpacity={0.3}/>
                            <stop offset="95%" stopColor="#8b5cf6" stopOpacity={0}/>
                        </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} dy={10} />
                    <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} tickFormatter={valueFormatter} />
                    <Tooltip contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} formatter={(value: number) => [valueFormatter(value), chart.metric]} />
                    <Legend verticalAlign="top" height={36} iconType="rect" />
                    <Area type="monotone" dataKey="value" stroke="#8b5cf6" fillOpacity={1} fill={`url(#color${chart.id})`} strokeWidth={2} name={chart.metric} />
                </ReAreaChart>
            ) : (
                // Bar
                <ReBarChart data={data} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} dy={10} />
                    <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#94a3b8'}} tickFormatter={valueFormatter} />
                    <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} formatter={(value: number) => [valueFormatter(value), chart.metric]} />
                    <Legend verticalAlign="top" height={36} iconType="circle" />
                    <Bar dataKey="value" fill="#10b981" radius={[4, 4, 0, 0]} barSize={40} name={chart.metric} />
                </ReBarChart>
            )}
        </ResponsiveContainer>
    );
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">

      {/* 1. Header & Global Filters */}
      <section className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-visible z-30 relative">
        <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50 rounded-t-xl">
            <div className="flex items-center gap-3">
                <div className="p-2 bg-purple-100 text-purple-600 rounded-lg"><LayoutGrid size={20} /></div>
                <input 
                    type="text" 
                    value={dashboardName} 
                    onChange={e => setDashboardName(e.target.value)}
                    className="text-lg font-black text-slate-800 bg-transparent outline-none border-b border-transparent focus:border-purple-300 hover:border-slate-300 transition-colors w-64"
                />
            </div>
            <button onClick={handleSaveDashboard} className="flex items-center gap-2 px-5 py-2 bg-slate-900 text-white text-xs font-bold rounded-lg hover:bg-slate-800 transition-all active:scale-95 shadow-md">
                <Save size={14} /> 保存布局
            </button>
        </div>

        <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase pl-1">日期范围</label>
                <div className="flex gap-2 h-10">
                    <input type="date" value={timeRange.start} onChange={e=>setTimeRange({...timeRange, start:e.target.value})} className="w-full px-2 bg-slate-50 border rounded-lg text-xs font-bold outline-none" />
                    <input type="date" value={timeRange.end} onChange={e=>setTimeRange({...timeRange, end:e.target.value})} className="w-full px-2 bg-slate-50 border rounded-lg text-xs font-bold outline-none" />
                </div>
            </div>

            <div className="space-y-1.5">
               <label className="text-[10px] font-black text-slate-400 uppercase pl-1">项目</label>
               <select className="w-full h-10 px-3 bg-slate-50 border rounded-lg text-sm font-bold outline-none" value={filters.project} onChange={e => setFilters({...filters, project: e.target.value})}>
                 {PROJECTS.map(p => <option key={p} value={p}>{p}</option>)}
               </select>
            </div>

            <MultiSelectDropdown 
                label="游戏" options={gameOptions} selected={filters.games} 
                onToggle={o => setFilters(prev => ({...prev, games: prev.games.includes(o) ? prev.games.filter(x=>x!==o) : [...prev.games, o]}))} 
                placeholder="全部游戏"
            />

            <MultiSelectDropdown 
                label="Tier & 地区" options={tierOptions} selected={filters.tiers} 
                onToggle={o => setFilters(prev => ({...prev, tiers: prev.tiers.includes(o) ? prev.tiers.filter(x=>x!==o) : [...prev.tiers, o]}))} 
                placeholder="全部 Tier"
            />
        </div>
      </section>

      {/* 2. Dashboard Grid (Dynamic Columns) */}
      <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 auto-rows-[350px]">

        {/* Render Charts */}
        {charts.map((chart) => (
            <div key={chart.id} className={`bg-white rounded-2xl shadow-sm border border-slate-200 p-5 flex flex-col group relative hover:shadow-lg transition-all ${getColSpan(chart.size)}`}>
                <div className="flex justify-between items-start mb-2 h-8">
                    <div className="flex items-center gap-2">
                        <div className={`p-1.5 rounded-md ${chart.type === 'number' ? 'bg-emerald-100 text-emerald-600' : 'bg-blue-50 text-blue-600'}`}>
                           {chart.type === 'line' && <LineChart size={14} />}
                           {chart.type === 'area' && <AreaChartIcon size={14} />}
                           {chart.type === 'bar' && <BarChart3 size={14} />}
                           {chart.type === 'pie' && <PieChart size={14} />}
                           {chart.type === 'number' && <TrendingUp size={14} />}
                        </div>
                        <div>
                            <h3 className="font-black text-slate-700 text-sm leading-tight">{chart.title}</h3>
                        </div>
                    </div>
                    <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity bg-slate-50 p-1 rounded-lg border border-slate-100">
                        <button onClick={() => handleOpenEdit(chart)} className="p-1.5 text-slate-400 hover:text-blue-600 rounded hover:bg-white transition-colors" title="Settings">
                            <Settings size={14} />
                        </button>
                        <button onClick={() => removeChart(chart.id)} className="p-1.5 text-slate-400 hover:text-red-500 rounded hover:bg-white transition-colors" title="Remove">
                            <Trash2 size={14} />
                        </button>
                    </div>
                </div>

                <div className="flex-1 w-full min-h-0">
                   {renderChartContent(chart)}
                </div>
            </div>
        ))}

        {/* Add Button Card */}
        <button 
            onClick={handleOpenAdd}
            className="col-span-1 border-3 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center gap-4 text-slate-400 hover:text-blue-600 hover:border-blue-300 hover:bg-blue-50/50 transition-all group min-h-[350px]"
        >
            <div className="w-16 h-16 rounded-full bg-slate-100 flex items-center justify-center group-hover:scale-110 group-hover:bg-blue-100 transition-all shadow-inner">
                <Plus size={32} className="group-hover:text-blue-600"/>
            </div>
            <span className="font-black text-sm uppercase tracking-wide">添加新图表 (Add Chart)</span>
        </button>
      </section>

      {/* 3. Add/Edit Chart Modal */}
      {isAddModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-3xl overflow-hidden animate-in zoom-in duration-300 flex flex-col max-h-[90vh]">
                <div className="px-6 py-4 border-b bg-slate-50/50 flex justify-between items-center">
                    <h3 className="font-black text-slate-800 uppercase text-sm tracking-wide">{editingChartId ? '编辑图表配置' : '配置新图表'}</h3>
                    <button onClick={() => setIsAddModalOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-all text-slate-400">
                        <X size={20}/>
                    </button>
                </div>

                <div className="p-8 overflow-y-auto custom-scrollbar">
                    {/* 1. Type Selection */}
                    <div className="mb-8">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block mb-3">1. 选择图表类型</label>
                        <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
                            {CHART_TYPES.map(t => {
                                const Icon = t.icon;
                                const isSelected = chartConfigForm.type === t.type;
                                return (
                                    <div 
                                        key={t.type} 
                                        onClick={() => setChartConfigForm({...chartConfigForm, type: t.type as ChartType})}
                                        className={`cursor-pointer rounded-xl border p-3 flex flex-col items-center gap-2 transition-all ${isSelected ? 'bg-blue-600 text-white border-blue-600 shadow-md transform scale-105' : 'bg-white text-slate-500 border-slate-200 hover:border-blue-300 hover:bg-blue-50'}`}
                                    >
                                        <Icon size={20} />
                                        <div className="text-center">
                                            <div className="text-[11px] font-black">{t.label}</div>
                                            <div className={`text-[9px] ${isSelected ? 'text-blue-100' : 'text-slate-400'}`}>{t.desc}</div>
                                        </div>
                                    </div>
                                )
                            })}
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        {/* 2. Data Config */}
                        <div className="space-y-5">
                             <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block border-b pb-2">2. 数据维度</label>

                             <div className="space-y-1.5">
                                <span className="text-xs font-bold text-slate-700">展示指标 (Metric)</span>
                                <select 
                                    className="w-full h-11 px-3 border border-slate-200 rounded-xl text-sm bg-white font-bold outline-none focus:border-blue-500"
                                    value={chartConfigForm.metric}
                                    onChange={e => setChartConfigForm({...chartConfigForm, metric: e.target.value})}
                                >
                                    {METRICS.map(m => <option key={m.value} value={m.value}>{m.label}</option>)}
                                </select>
                            </div>

                            {/* Conditional Days Select */}
                            {METRICS.find(m => m.value === chartConfigForm.metric)?.hasDays && (
                                <div className="space-y-1.5 animate-in fade-in slide-in-from-top-2">
                                    <span className="text-xs font-bold text-slate-700">同期群天数 (Cohort Day)</span>
                                    <div className="flex flex-wrap gap-2">
                                        {METRIC_DAYS.map(day => (
                                            <button
                                                key={day}
                                                onClick={() => setChartConfigForm({...chartConfigForm, metricDay: day})}
                                                className={`px-3 py-1.5 rounded-lg text-xs font-bold border transition-all ${chartConfigForm.metricDay === day ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-500 border-slate-200 hover:bg-indigo-50'}`}
                                            >
                                                D{day}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div className="space-y-1.5">
                                <span className="text-xs font-bold text-slate-700">分组维度 (Dimension/X-Axis)</span>
                                <select 
                                    className="w-full h-11 px-3 border border-slate-200 rounded-xl text-sm bg-white font-bold outline-none focus:border-blue-500"
                                    value={chartConfigForm.dimension}
                                    onChange={e => setChartConfigForm({...chartConfigForm, dimension: e.target.value})}
                                >
                                    {DIMENSIONS.map(d => <option key={d.value} value={d.value}>{d.label}</option>)}
                                </select>
                            </div>
                        </div>

                        {/* 3. Appearance Config */}
                        <div className="space-y-5">
                             <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block border-b pb-2">3. 外观展示</label>

                             <div className="space-y-1.5">
                                <span className="text-xs font-bold text-slate-700">卡片尺寸 (Grid Size)</span>
                                <div className="grid grid-cols-2 gap-3">
                                    {[
                                        {v: 'small', l: '小 (1/4)', i: Minimize2}, 
                                        {v: 'medium', l: '中 (1/2)', i: LayoutGrid}, 
                                        {v: 'large', l: '大 (3/4)', i: Maximize2},
                                        {v: 'full', l: '全宽 (Full)', i: Maximize2}
                                    ].map(opt => (
                                        <button
                                            key={opt.v}
                                            onClick={() => setChartConfigForm({...chartConfigForm, size: opt.v as CardSize})}
                                            className={`flex items-center gap-2 px-3 py-2.5 rounded-xl border text-xs font-bold transition-all ${chartConfigForm.size === opt.v ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 hover:bg-slate-50'}`}
                                        >
                                            <opt.i size={14} /> {opt.l}
                                        </button>
                                    ))}
                                </div>
                             </div>

                             <div className="space-y-1.5">
                                <span className="text-xs font-bold text-slate-700">自定义标题</span>
                                <input 
                                    type="text" 
                                    className="w-full h-11 px-4 border border-slate-200 rounded-xl text-sm font-bold outline-none focus:border-blue-500"
                                    placeholder="自动生成 (Auto)"
                                    value={chartConfigForm.title || ''}
                                    onChange={e => setChartConfigForm({...chartConfigForm, title: e.target.value})}
                                />
                            </div>
                        </div>
                    </div>
                </div>

                <div className="px-8 py-5 bg-slate-50 border-t flex justify-end gap-3">
                    <button onClick={() => setIsAddModalOpen(false)} className="px-6 py-2.5 font-bold text-slate-500 text-xs hover:text-slate-700">取消</button>
                    <button onClick={handleSaveChartConfig} className="px-10 py-2.5 bg-blue-600 text-white font-black text-xs rounded-xl shadow-lg hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
                        <Save size={16} /> {editingChartId ? '保存修改' : '确认添加'}
                    </button>
                </div>
            </div>
        </div>
      )}

    </div>
  );
};

