                    if(e.target.value === 'daily') setDateRange({start: '2026-02-01', end: '2026-02-07'});
                    if(e.target.value === 'monthly') setDateRange({start: '2026-01', end: '2026-06'});
                    if(e.target.value === 'yearly') setDateRange({start: '2024', end: '2026'});
