const GENERATE_DAYS = () => {
  const days = [];
  for (let i = 1; i <= 90; i++) days.push(String(i));
  // Add 180 for the ROI requirement
  days.push('180');
  for (let i = 90; i <= 720; i += 30) {
    if (!days.includes(String(i))) days.push(String(i));
  }
  return days.sort((a,b) => parseInt(a) - parseInt(b));
};
